#include <stdio.h>

long factorial(int n) {
    long result = 1;
    for (int i = 1; i <= n; i++) {
        result *= i;
    }
    return result;
}

int main() {
    int a;
    scanf("%d", &a);
    printf("%ld", factorial(a) / factorial(a - 5) / 120 * a * (a - 1) * (a - 2) * (a - 3) * (a - 4));
